import Database from "better-sqlite3";
import type { Database as SqliteDatabase } from "better-sqlite3";

export const db: SqliteDatabase = new Database(process.env.DB_FILE ?? "data.db");

db.pragma("foreign_keys = ON");

export function initializeDatabase(database: SqliteDatabase = db): void {
  database.pragma("foreign_keys = ON");

  database
    .prepare(
      `
      CREATE TABLE IF NOT EXISTS folders (
        id INTEGER PRIMARY KEY,
        name TEXT NOT NULL,
        created_at TEXT NOT NULL,
        updated_at TEXT NOT NULL
      )
    `,
    )
    .run();

  database
    .prepare(
      `
      CREATE TABLE IF NOT EXISTS bookmarks (
        id INTEGER PRIMARY KEY,
        url TEXT NOT NULL,
        title TEXT NOT NULL,
        description TEXT,
        folder_id INTEGER REFERENCES folders(id) ON DELETE SET NULL,
        created_at TEXT NOT NULL,
        updated_at TEXT NOT NULL
      )
    `,
    )
    .run();

  const bookmarkColumns = database
    .prepare("PRAGMA table_info(bookmarks)")
    .all() as Array<{ name: string }>;

  if (!bookmarkColumns.some((column) => column.name === "folder_id")) {
    database
      .prepare(
        "ALTER TABLE bookmarks ADD COLUMN folder_id INTEGER REFERENCES folders(id) ON DELETE SET NULL",
      )
      .run();
  }
}

import { Router } from "express";
import type { Database as SqliteDatabase } from "better-sqlite3";
import type { Request, Response } from "express";

type Folder = {
  id: number;
  name: string;
  created_at: string;
  updated_at: string;
};

type Bookmark = {
  id: number;
  url: string;
  title: string;
  description: string | null;
  folder_id: number | null;
  created_at: string;
  updated_at: string;
};

type FolderInput = {
  name?: unknown;
};

function sendValidationError(res: Response, message: string): void {
  res.status(400).json({ error: message });
}

function isNonEmptyString(value: unknown): value is string {
  return typeof value === "string" && value.trim().length > 0;
}

function parseFolderId(req: Request): number | null {
  const id = Number(req.params.id);
  return Number.isInteger(id) && id > 0 ? id : null;
}

export function createFoldersRouter(db: SqliteDatabase): Router {
  const router = Router();

  router.post("/", (req, res) => {
    const body = req.body as FolderInput;

    if (!isNonEmptyString(body.name)) {
      sendValidationError(res, "name is required");
      return;
    }

    const now = new Date().toISOString();
    const result = db
      .prepare(
        `
        INSERT INTO folders (name, created_at, updated_at)
        VALUES (?, ?, ?)
      `,
      )
      .run(body.name.trim(), now, now);

    const folder = db
      .prepare("SELECT * FROM folders WHERE id = ?")
      .get(result.lastInsertRowid) as Folder;

    res.status(201).json(folder);
  });

  router.get("/", (_req, res) => {
    const folders = db
      .prepare("SELECT * FROM folders ORDER BY id ASC")
      .all() as Folder[];

    res.status(200).json(folders);
  });

  router.get("/:id", (req, res) => {
    const id = parseFolderId(req);

    if (id === null) {
      res.status(404).json({ error: "folder not found" });
      return;
    }

    const folder = db
      .prepare("SELECT * FROM folders WHERE id = ?")
      .get(id) as Folder | undefined;

    if (!folder) {
      res.status(404).json({ error: "folder not found" });
      return;
    }

    const bookmarks = db
      .prepare("SELECT * FROM bookmarks WHERE folder_id = ? ORDER BY id ASC")
      .all(id) as Bookmark[];

    res.status(200).json({ ...folder, bookmarks });
  });

  router.put("/:id", (req, res) => {
    const id = parseFolderId(req);

    if (id === null) {
      res.status(404).json({ error: "folder not found" });
      return;
    }

    const existing = db
      .prepare("SELECT * FROM folders WHERE id = ?")
      .get(id) as Folder | undefined;

    if (!existing) {
      res.status(404).json({ error: "folder not found" });
      return;
    }

    const body = req.body as FolderInput;

    if (!isNonEmptyString(body.name)) {
      sendValidationError(res, "name is required");
      return;
    }

    db.prepare(
      `
      UPDATE folders
      SET name = ?, updated_at = ?
      WHERE id = ?
    `,
    ).run(body.name.trim(), new Date().toISOString(), id);

    const folder = db
      .prepare("SELECT * FROM folders WHERE id = ?")
      .get(id) as Folder;

    res.status(200).json(folder);
  });

  router.delete("/:id", (req, res) => {
    const id = parseFolderId(req);

    if (id === null) {
      res.status(404).json({ error: "folder not found" });
      return;
    }

    const existing = db
      .prepare("SELECT id FROM folders WHERE id = ?")
      .get(id) as { id: number } | undefined;

    if (!existing) {
      res.status(404).json({ error: "folder not found" });
      return;
    }

    const deleteFolder = db.transaction(() => {
      db.prepare("UPDATE bookmarks SET folder_id = NULL WHERE folder_id = ?").run(
        id,
      );
      db.prepare("DELETE FROM folders WHERE id = ?").run(id);
    });

    deleteFolder();

    res.status(204).send();
  });

  return router;
}

import { Router } from "express";
import type { Database as SqliteDatabase } from "better-sqlite3";
import type { Request, Response } from "express";

type Bookmark = {
  id: number;
  url: string;
  title: string;
  description: string | null;
  folder_id: number | null;
  created_at: string;
  updated_at: string;
};

type BookmarkInput = {
  url?: unknown;
  title?: unknown;
  description?: unknown;
  folder_id?: unknown;
};

function sendValidationError(res: Response, message: string): void {
  res.status(400).json({ error: message });
}

function isNonEmptyString(value: unknown): value is string {
  return typeof value === "string" && value.trim().length > 0;
}

function parseBookmarkId(req: Request): number | null {
  const id = Number(req.params.id);
  return Number.isInteger(id) && id > 0 ? id : null;
}

function normalizeDescription(value: unknown): string | null {
  if (value === undefined || value === null) {
    return null;
  }

  if (typeof value !== "string") {
    return String(value);
  }

  return value;
}

function parseOptionalFolderId(value: unknown): number | null | undefined | false {
  if (value === undefined) {
    return undefined;
  }

  if (value === null) {
    return null;
  }

  const id = Number(value);
  return Number.isInteger(id) && id > 0 ? id : false;
}

function folderExists(db: SqliteDatabase, folderId: number): boolean {
  const folder = db
    .prepare("SELECT id FROM folders WHERE id = ?")
    .get(folderId) as { id: number } | undefined;

  return folder !== undefined;
}

function validateFolderId(
  db: SqliteDatabase,
  res: Response,
  value: unknown,
): number | null | undefined | false {
  const folderId = parseOptionalFolderId(value);

  if (folderId === false) {
    sendValidationError(res, "folder_id must be a positive integer");
    return false;
  }

  if (folderId === undefined || folderId === null) {
    return folderId;
  }

  if (!folderExists(db, folderId)) {
    sendValidationError(res, "folder_id must reference an existing folder");
    return false;
  }

  return folderId;
}

export function createBookmarksRouter(db: SqliteDatabase): Router {
  const router = Router();

  router.post("/", (req, res) => {
    const body = req.body as BookmarkInput;

    if (!isNonEmptyString(body.url)) {
      sendValidationError(res, "url is required");
      return;
    }

    if (!isNonEmptyString(body.title)) {
      sendValidationError(res, "title is required");
      return;
    }

    const folderId = validateFolderId(db, res, body.folder_id);

    if (folderId === false) {
      return;
    }

    const now = new Date().toISOString();
    const result = db
      .prepare(
        `
        INSERT INTO bookmarks (url, title, description, folder_id, created_at, updated_at)
        VALUES (?, ?, ?, ?, ?, ?)
      `,
      )
      .run(
        body.url.trim(),
        body.title.trim(),
        normalizeDescription(body.description),
        folderId ?? null,
        now,
        now,
      );

    const bookmark = db
      .prepare("SELECT * FROM bookmarks WHERE id = ?")
      .get(result.lastInsertRowid) as Bookmark;

    res.status(201).json(bookmark);
  });

  router.get("/", (_req, res) => {
    const bookmarks = db
      .prepare("SELECT * FROM bookmarks ORDER BY id ASC")
      .all() as Bookmark[];

    res.status(200).json(bookmarks);
  });

  router.get("/:id", (req, res) => {
    const id = parseBookmarkId(req);

    if (id === null) {
      res.status(404).json({ error: "bookmark not found" });
      return;
    }

    const bookmark = db
      .prepare("SELECT * FROM bookmarks WHERE id = ?")
      .get(id) as Bookmark | undefined;

    if (!bookmark) {
      res.status(404).json({ error: "bookmark not found" });
      return;
    }

    res.status(200).json(bookmark);
  });

  router.put("/:id", (req, res) => {
    const id = parseBookmarkId(req);

    if (id === null) {
      res.status(404).json({ error: "bookmark not found" });
      return;
    }

    const existing = db
      .prepare("SELECT * FROM bookmarks WHERE id = ?")
      .get(id) as Bookmark | undefined;

    if (!existing) {
      res.status(404).json({ error: "bookmark not found" });
      return;
    }

    const body = req.body as BookmarkInput;

    if (body.url !== undefined && !isNonEmptyString(body.url)) {
      sendValidationError(res, "url must be a non-empty string");
      return;
    }

    if (body.title !== undefined && !isNonEmptyString(body.title)) {
      sendValidationError(res, "title must be a non-empty string");
      return;
    }

    const updatedAt = new Date().toISOString();
    const nextUrl = body.url === undefined ? existing.url : body.url.trim();
    const nextTitle =
      body.title === undefined ? existing.title : body.title.trim();
    const nextDescription =
      body.description === undefined
        ? existing.description
        : normalizeDescription(body.description);
    const folderId = validateFolderId(db, res, body.folder_id);

    if (folderId === false) {
      return;
    }

    const nextFolderId =
      body.folder_id === undefined ? existing.folder_id : folderId;

    db.prepare(
      `
      UPDATE bookmarks
      SET url = ?, title = ?, description = ?, folder_id = ?, updated_at = ?
      WHERE id = ?
    `,
    ).run(nextUrl, nextTitle, nextDescription, nextFolderId, updatedAt, id);

    const bookmark = db
      .prepare("SELECT * FROM bookmarks WHERE id = ?")
      .get(id) as Bookmark;

    res.status(200).json(bookmark);
  });

  router.delete("/:id", (req, res) => {
    const id = parseBookmarkId(req);

    if (id === null) {
      res.status(404).json({ error: "bookmark not found" });
      return;
    }

    const result = db.prepare("DELETE FROM bookmarks WHERE id = ?").run(id);

    if (result.changes === 0) {
      res.status(404).json({ error: "bookmark not found" });
      return;
    }

    res.status(204).send();
  });

  return router;
}

