describe("bookmark CRUD API", () => {
  beforeEach(async () => {
    if (!server) {
      server = app.listen(0);
      await new Promise<void>((resolve) => server.once("listening", resolve));
      const address = server.address();

      if (!address || typeof address === "string") {
        throw new Error("test server did not bind to a TCP port");
      }

      baseUrl = `http://127.0.0.1:${address.port}`;
    }
  });

  it("keeps the health endpoint working", async () => {
    const response = await request("/health");

    expect(response.status).toBe(200);
    await expect(response.json()).resolves.toEqual({ status: "ok" });
  });

  it("creates, lists, gets, updates, and deletes bookmarks", async () => {
    const createResponse = await request("/bookmarks", {
      method: "POST",
      body: JSON.stringify({
        url: "https://example.com",
        title: "Test",
        description: "Example bookmark",
      }),
    });

    expect(createResponse.status).toBe(201);
    const created = (await createResponse.json()) as BookmarkResponse;
    expect(created).toMatchObject({
      id: 1,
      url: "https://example.com",
      title: "Test",
      description: "Example bookmark",
      folder_id: null,
    });
    expect(created.created_at).toEqual(expect.any(String));
    expect(created.updated_at).toEqual(expect.any(String));

    const listResponse = await request("/bookmarks");
    expect(listResponse.status).toBe(200);
    await expect(listResponse.json()).resolves.toEqual([created]);

    const getResponse = await request("/bookmarks/1");
    expect(getResponse.status).toBe(200);
    await expect(getResponse.json()).resolves.toEqual(created);

    const updateResponse = await request("/bookmarks/1", {
      method: "PUT",
      body: JSON.stringify({ title: "Updated" }),
    });
    expect(updateResponse.status).toBe(200);
    const updated = (await updateResponse.json()) as BookmarkResponse;
    expect(updated).toMatchObject({
      id: 1,
      url: "https://example.com",
      title: "Updated",
      description: "Example bookmark",
      created_at: created.created_at,
    });

    const deleteResponse = await request("/bookmarks/1", { method: "DELETE" });
    expect(deleteResponse.status).toBe(204);

    const missingResponse = await request("/bookmarks/1");
    expect(missingResponse.status).toBe(404);
  });

  it("returns 400 for missing or empty required create fields", async () => {
    const missingTitle = await request("/bookmarks", {
      method: "POST",
      body: JSON.stringify({ url: "https://example.com" }),
    });
    expect(missingTitle.status).toBe(400);

    const missingUrl = await request("/bookmarks", {
      method: "POST",
      body: JSON.stringify({ title: "No URL" }),
    });
    expect(missingUrl.status).toBe(400);

    const emptyTitle = await request("/bookmarks", {
      method: "POST",
      body: JSON.stringify({ url: "https://example.com", title: "" }),
    });
    expect(emptyTitle.status).toBe(400);
  });

  it("returns 404 for missing bookmarks on read, update, and delete", async () => {
    const getResponse = await request("/bookmarks/9999");
    expect(getResponse.status).toBe(404);

    const updateResponse = await request("/bookmarks/9999", {
      method: "PUT",
      body: JSON.stringify({ title: "Updated" }),
    });
    expect(updateResponse.status).toBe(404);

    const deleteResponse = await request("/bookmarks/9999", {
      method: "DELETE",
    });
    expect(deleteResponse.status).toBe(404);
  });

  it("creates, lists, gets, updates, and deletes folders", async () => {
    const createResponse = await request("/folders", {
      method: "POST",
      body: JSON.stringify({ name: "Reading" }),
    });

    expect(createResponse.status).toBe(201);
    const created = (await createResponse.json()) as FolderResponse;
    expect(created).toMatchObject({
      id: 1,
      name: "Reading",
    });
    expect(created.created_at).toEqual(expect.any(String));
    expect(created.updated_at).toEqual(expect.any(String));

    const listResponse = await request("/folders");
    expect(listResponse.status).toBe(200);
    await expect(listResponse.json()).resolves.toEqual([created]);

    const bookmarkResponse = await request("/bookmarks", {
      method: "POST",
      body: JSON.stringify({
        url: "https://example.com",
        title: "Foldered bookmark",
        folder_id: created.id,
      }),
    });
    expect(bookmarkResponse.status).toBe(201);
    const bookmark = (await bookmarkResponse.json()) as BookmarkResponse;
    expect(bookmark.folder_id).toBe(created.id);

    const getResponse = await request("/folders/1");
    expect(getResponse.status).toBe(200);
    await expect(getResponse.json()).resolves.toEqual({
      ...created,
      bookmarks: [bookmark],
    });

    const updateResponse = await request("/folders/1", {
      method: "PUT",
      body: JSON.stringify({ name: "Reference" }),
    });
    expect(updateResponse.status).toBe(200);
    const updated = (await updateResponse.json()) as FolderResponse;
    expect(updated).toMatchObject({
      id: 1,
      name: "Reference",
      created_at: created.created_at,
    });

    const deleteResponse = await request("/folders/1", { method: "DELETE" });
    expect(deleteResponse.status).toBe(204);

    const unfolderedResponse = await request(`/bookmarks/${bookmark.id}`);
    expect(unfolderedResponse.status).toBe(200);
    const unfoldered = (await unfolderedResponse.json()) as BookmarkResponse;
    expect(unfoldered.folder_id).toBeNull();

    const missingResponse = await request("/folders/1");
    expect(missingResponse.status).toBe(404);
  });

  it("validates folder fields and missing folders", async () => {
    const missingName = await request("/folders", {
      method: "POST",
      body: JSON.stringify({}),
    });
    expect(missingName.status).toBe(400);

    const emptyName = await request("/folders", {
      method: "POST",
      body: JSON.stringify({ name: "" }),
    });
    expect(emptyName.status).toBe(400);

    const missingGet = await request("/folders/9999");
    expect(missingGet.status).toBe(404);

    const missingUpdate = await request("/folders/9999", {
      method: "PUT",
      body: JSON.stringify({ name: "Updated" }),
    });
    expect(missingUpdate.status).toBe(404);

    const missingDelete = await request("/folders/9999", { method: "DELETE" });
    expect(missingDelete.status).toBe(404);
  });

  it("returns 400 when bookmark folder_id does not reference a folder", async () => {
    const createResponse = await request("/bookmarks", {
      method: "POST",
      body: JSON.stringify({
        url: "https://example.com",
        title: "Missing folder",
        folder_id: 9999,
      }),
    });
    expect(createResponse.status).toBe(400);

    const bookmarkResponse = await request("/bookmarks", {
      method: "POST",
      body: JSON.stringify({
        url: "https://example.com",
        title: "Unfoldered",
      }),
    });

    });
    expect(bookmarkResponse.status).toBe(201);

    const updateResponse = await request("/bookmarks/1", {
      method: "PUT",
      body: JSON.stringify({ folder_id: 9999 }),
    });
    expect(updateResponse.status).toBe(400);
  });
});

import { Router } from "express";
import type { Database as SqliteDatabase } from "better-sqlite3";
import type { Request, Response } from "express";

type Folder = {
  id: number;
  user_id: number;
  name: string;
  created_at: string;
  updated_at: string;
};

type Bookmark = {
  id: number;
  user_id: number;
  url: string;
  title: string;
  description: string | null;
  folder_id: number | null;
  created_at: string;
  updated_at: string;
};

type FolderInput = {
  name?: unknown;
};

function sendValidationError(res: Response, message: string): void {
  res.status(400).json({ error: message });
}

function isNonEmptyString(value: unknown): value is string {
  return typeof value === "string" && value.trim().length > 0;
}

function parseFolderId(req: Request): number | null {
  const id = Number(req.params.id);
  return Number.isInteger(id) && id > 0 ? id : null;
}

function getAuthenticatedUserId(req: Request, res: Response): number | null {
  if (typeof req.userId !== "number") {
    res.status(401).json({ error: "missing or invalid token" });
    return null;
  }

  return req.userId;
}

export function createFoldersRouter(db: SqliteDatabase): Router {
  const router = Router();

  router.post("/", (req, res) => {
    const userId = getAuthenticatedUserId(req, res);

    if (userId === null) {
      return;
    }

    const body = req.body as FolderInput;

    if (!isNonEmptyString(body.name)) {
      sendValidationError(res, "name is required");
      return;
    }

    const now = new Date().toISOString();
    const result = db
      .prepare(
        `
        INSERT INTO folders (user_id, name, created_at, updated_at)
        VALUES (?, ?, ?, ?)
      `,
      )
      .run(userId, body.name.trim(), now, now);

    const folder = db
      .prepare("SELECT * FROM folders WHERE id = ?")
      .get(result.lastInsertRowid) as Folder;

    res.status(201).json(folder);
  });

  router.get("/", (req, res) => {
    const userId = getAuthenticatedUserId(req, res);

    if (userId === null) {
      return;
    }

    const folders = db
      .prepare("SELECT * FROM folders WHERE user_id = ? ORDER BY id ASC")
      .all(userId) as Folder[];

    res.status(200).json(folders);
  });

  router.get("/:id", (req, res) => {
    const userId = getAuthenticatedUserId(req, res);

    if (userId === null) {
      return;
    }

    const id = parseFolderId(req);

    if (id === null) {
      res.status(404).json({ error: "folder not found" });
      return;
    }

    const folder = db
      .prepare("SELECT * FROM folders WHERE id = ? AND user_id = ?")
      .get(id, userId) as Folder | undefined;

    if (!folder) {
      res.status(404).json({ error: "folder not found" });
      return;
    }

    const bookmarks = db
      .prepare(
        "SELECT * FROM bookmarks WHERE folder_id = ? AND user_id = ? ORDER BY id ASC",
      )
      .all(id, userId) as Bookmark[];

    res.status(200).json({ ...folder, bookmarks });
  });

  router.put("/:id", (req, res) => {
    const userId = getAuthenticatedUserId(req, res);

    if (userId === null) {
      return;
    }

    const id = parseFolderId(req);

    if (id === null) {
      res.status(404).json({ error: "folder not found" });
      return;
    }

    const existing = db
      .prepare("SELECT * FROM folders WHERE id = ? AND user_id = ?")
      .get(id, userId) as Folder | undefined;

    if (!existing) {
      res.status(404).json({ error: "folder not found" });
      return;
    }

    const body = req.body as FolderInput;

    if (!isNonEmptyString(body.name)) {
      sendValidationError(res, "name is required");
      return;
    }

    db.prepare(
      `
      UPDATE folders
      SET name = ?, updated_at = ?
      WHERE id = ? AND user_id = ?
    `,
    ).run(body.name.trim(), new Date().toISOString(), id, userId);

    const folder = db
      .prepare("SELECT * FROM folders WHERE id = ? AND user_id = ?")
      .get(id, userId) as Folder;

    res.status(200).json(folder);
  });

  router.delete("/:id", (req, res) => {
    const userId = getAuthenticatedUserId(req, res);

    if (userId === null) {
      return;
